collab/two-tabs-live.text:
import { AfterViewInit, Component } from '@angular/core';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { BroadcastChannelTransport } from '@grafloria/engine';
import { markReady } from '../demo-ready';

/** Real multiplayer with no server: two canvases in one page, each joined to
 *  the same room over BroadcastChannel via [collab]. Drag a node on the left —
 *  the right converges through the engine's per-property CRDT, with presence
 *  cursors painted for the remote actor. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent],
  templateUrl: './two-tabs-live.component.html',
})
export class TwoTabsLiveComponent implements AfterViewInit {
  private room = 'ng-collab-' + Math.random().toString(36).slice(2, 8);
  nodesA = [
    { id: 'a', position: { x: 60, y: 60 },  size: { width: 150, height: 66 }, data: { label: 'Ingest' } },
    { id: 'b', position: { x: 320, y: 60 }, size: { width: 150, height: 66 }, data: { label: 'Publish' } },
  ];
  edgesA = [{ id: 'e1', source: 'a', target: 'b' }];
  nodesB = structuredClone(this.nodesA);
  edgesB = structuredClone(this.edgesA);
  collabA = { transport: new BroadcastChannelTransport({ name: this.room, actor: 'ana' }), actor: 'ana', presence: { name: 'Ana' } };
  collabB = { transport: new BroadcastChannelTransport({ name: this.room, actor: 'ben' }), actor: 'ben', presence: { name: 'Ben' } };
  ngAfterViewInit() { markReady(); }
}

collab/comments.text:
import { AfterViewInit, Component, viewChild } from '@angular/core';
import { DiagramCanvasComponent, GrafloriaCommentPanelComponent } from '@grafloria/renderer-angular';
import type { CommentStore } from '@grafloria/engine';
import { markReady } from '../demo-ready';

/** Anchored comment threads: [comments]="true" turns the capability on; the
 *  conversation panel binds to the canvas's own CommentStore. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent, GrafloriaCommentPanelComponent],
  templateUrl: './comments.component.html',
})
export class CommentsComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  store: CommentStore | null = null;
  nodes = [
    { id: 'design', position: { x: 80, y: 120 },  size: { width: 150, height: 66 }, data: { label: 'Design' } },
    { id: 'review', position: { x: 330, y: 120 }, size: { width: 150, height: 66 }, data: { label: 'Review' } },
    { id: 'ship',   position: { x: 580, y: 120 }, size: { width: 150, height: 66 }, data: { label: 'Ship' } },
  ];
  edges = [
    { id: 'e1', source: 'design', target: 'review' },
    { id: 'e2', source: 'review', target: 'ship' },
  ];
  ngAfterViewInit() {
    this.store = this.canvas().getCommentStore();
    if (this.store) {
      const t = this.store.createThread({ kind: 'node', id: 'review' }, 'Can we tighten the hero copy?');
      this.store.reply(t, 'On it — draft by Friday.');
    }
    markReady();
  }
}

misc/mermaid-text.text:
import { AfterViewInit, Component, viewChild } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { DiagramCanvasComponent } from '@grafloria/renderer-angular';
import { markReady } from '../demo-ready';

/** Diagram-as-text: exportText() writes Mermaid-style text from the live
 *  canvas; loadText() reconciles edited text back INTO the same instance —
 *  positions survive through the lossless sidecar. */
@Component({
  standalone: true,
  imports: [DiagramCanvasComponent, FormsModule],
  templateUrl: './mermaid-text.component.html',
})
export class MermaidTextComponent implements AfterViewInit {
  canvas = viewChild.required(DiagramCanvasComponent);
  text = '';
  nodes = [
    { id: 'start', position: { x: 80, y: 60 },  size: { width: 140, height: 60 }, data: { label: 'Start' } },
    { id: 'work',  position: { x: 320, y: 60 }, size: { width: 140, height: 60 }, data: { label: 'Work' } },
    { id: 'done',  position: { x: 560, y: 60 }, size: { width: 140, height: 60 }, data: { label: 'Done' } },
  ];
  edges = [
    { id: 'e1', source: 'start', target: 'work' },
    { id: 'e2', source: 'work', target: 'done' },
  ];
  export() { this.text = this.canvas().exportText(); }
  load() { this.canvas().loadText(this.text); }
  ngAfterViewInit() { this.export(); markReady(); }
}

